var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 덕분에 늦지 않게 모두 정리한 것 같네요.","JPN":"ハハ、おかげで時間内に処理できたようですね。","ENG":"Hah hah, we've managed to clear the site before it was too late.","TWN":"哈哈，多虧了米娜小姐，我們準時解決了呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시 미나 양의 잠재력은 대단하다니까요?","JPN":"やっぱり、ミナさんの潜在能力はすごいですね？","ENG":"I knew you had great potential in you.","TWN":"米娜小姐果然潛力無窮呢！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 몸은 좀 어때요?","JPN":"ミナさん、体調はどうですか？","ENG":"How are you feeling, Mina?","TWN":"米娜小姐，妳身體還好嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......아파.","JPN":"……だるい。","ENG":"It hurts.","TWN":"……痛。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"온 몸이 두들겨 맞은 것 같아......","JPN":"全身打撲のような感覚だよ……","ENG":"I feel like my whole body was beaten to a pulp.","TWN":"好像全身都被揍了一頓……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 나한테 무슨 짓을 한 거야?","JPN":"いったい私に何をしたの？","ENG":"What did you do to me?","TWN":"你到底對我做了什麼？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"검을 깨웠다는 건 또 무슨 소리고?","JPN":"剣を呼び起こしたって、どういう意味？","ENG":"And what does it mean to awaken the sword?","TWN":"什麼叫作劍被喚醒了？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이 가진 클리포트 인자는 말하자면 푹 젖은 화약 같은 거라서요.","JPN":"ミナさんが持つクリフォト・ファクターは、言ってしまえば、ずぶ濡れの火薬のようなものなんです。","ENG":"To put it simply, the Qliphoth Factor in your body is like a batch of gunpowder drenched in water.","TWN":"米娜小姐擁有的逆卡巴拉因子就像濕透了的火藥一樣。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"순도는 말도 안되게 높지만...... 활성화가 어려워요.","JPN":"純度はあり得ないほど高いですが……活性化が難しいので、","ENG":"It's ridiculously high in purity, but it's extremely difficult to activate.","TWN":"雖然純度極高……但要使它活性化卻很難。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 자극을 줘서 격발시킬 뇌관이 필요한 거죠.","JPN":"刺激を与えて撃発させるような雷管が必要です。","ENG":"That's why you needed a stimulus, or a detonator, to make it work.","TWN":"所以需要給予它刺激，使它引爆雷管。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 검이...... 그 뇌관이라고?","JPN":"この剣が……その雷管なの？","ENG":"And this sword was the stimulus, you're saying?","TWN":"這把劍……就是雷管嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가능성은 높다고 생각했죠.","JPN":"可能性は高いと思いました。","ENG":"I thought it was highly probable, at least.","TWN":"我認為可能性很高。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"일반적으로 이런 <color=#ffd34c>마검</color> 계열의 무기는 사용자로부터 필요한 힘을 강제 추출하는 기능을 가지고 있으니까요.","JPN":"普通、こういう<color=#ffd34c>魔剣</color>の類は、\\n必要な力を持ち主から強制的に抽出する機能を持っていますからね。","ENG":"An <color=#ffd34c>evil sword</color> like this normally operates based on the energy it juices out from its owner.","TWN":"因為一般來說，這種<color=#ffd34c>魔劍</color>系列的武器，都會從使用者身上強制抽出它所需要的力量。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 정도가 지나치면 모든 힘을 빨아 먹히고 껍데기만 남을 수도 있겠지만......","JPN":"度が過ぎると、すべての力を吸い取られて、生ける屍みたいになるかもしれませんが……","ENG":"The sword would suck its owner dry if whoever owns it were weak...","TWN":"如果超過一定限度，有可能會被吸食掉所有力量，只剩下一個空殼……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양의 잠재력을 생각한다면...... 그냥 좀 불편한 정도일 겁니다.","JPN":"ミナさんの潜在能力を考慮すると……少し違和感がある程度だと思います。","ENG":"But considering the power latent within you, it'd cause no more than slight uneasiness,","TWN":"但考慮到米娜小姐的潛力……這只是稍微有點不便而已吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그것도 차차 가라앉겠죠.","JPN":"それも次第に落ち着くでしょうね。","ENG":"which will soon go away as time passes.","TWN":"而且，痛覺也會逐漸緩解的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼...... 그 클리포트인가 뭔가 하는 힘을 사용할 수 있는 거야?","JPN":"じゃあ……そのクリフォトなんとかとやらを使えるようになるの？","ENG":"Then... Can I now use the power of Qliphoth whatever?","TWN":"所以……這個逆卡巴拉因子可以用來做什麼呢？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그건 미나 양의 노력에 달렸죠.","JPN":"それはミナさんの努力次第ですね。","ENG":"That depends on your efforts, Mina.","TWN":"那就端看米娜小姐的努力了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 적어도 그 검을 매개체로 해서 힘을 끌어내는 것 정도는 가능할 겁니다.","JPN":"ただ、少なくとも、その剣を媒介にして力を引き出すことくらいはできると思います。","ENG":"But at least you could use the sword as the medium and draw the power from it.","TWN":"但至少，妳可以用劍當媒介引出力量。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"물론 그 검과 미나양의 역량이 감당할 수 있는 한도 내에서겠지만요.","JPN":"もちろん、その剣やミナさんが持ちこたえられる限度内でですが。","ENG":"Of course, it'd be within the limits of your capabilities.","TWN":"當然，這是在劍和米娜小姐的能力有餘裕的情況下。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......어째서 내게 이런 일을 해 주는 거지?","JPN":"……どうして私にこんなことをしてくれるの？","ENG":"Why are you doing all this for me?","TWN":"……你為什麼要幫我做這些事情？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 선배의 피에 클리포트 인자가 있다는 건 또 무슨 소리야?","JPN":"それから、先輩の血にクリフォト・ファクターが含まれているって、どういうこと？","ENG":"And how do you have the Qliphoth Factor running in your blood?","TWN":"還有，前輩的血裡有逆卡巴拉因子又是在說什麼啊？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"클리포트 인자라는 이름을 알게 된 건 저도 최근의 일입니다.","JPN":"クリフォト・ファクターという名前を知ったのは、僕も最近なんです。","ENG":"It was not until recently that I familiarized myself with the name, Qliphoth Factor.","TWN":"逆卡巴拉因子這個名字，我也是最近才知道的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가 알고 있던 이름은......","JPN":"僕の知る名前は……","ENG":"Before that, I called it...","TWN":"我原來知道的名字是……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"용혈이었어요.","JPN":"龍血でした。","ENG":"the Dragon Blood.","TWN":"龍血。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"용혈?","JPN":"龍血？","ENG":"Huh?","TWN":"龍血？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......용의 피라는 뜻이야?","JPN":"……「龍の血」という意味？","ENG":"Dragon Blood?","TWN":"……是指龍的血液？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 조금 유치하죠?","JPN":"ハハハ、少し中2っぽいですかね？","ENG":"Hah hah, a bit cheesy, right?","TWN":"哈哈，有點幼稚對吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 너무 놀리진 말아주세요.","JPN":"でも、あまりからかわないでくださいね。","ENG":"But please don't be too harsh on me because of it.","TWN":"但是也別嘲笑我嘛。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도 전해들은 거라서요.","JPN":"僕も聞いただけなんです。","ENG":"That was the name they told me.","TWN":"我也是聽說的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"전해 들었다고......? 누구에게?","JPN":"聞いた……？　誰から？","ENG":"They? Who's they?","TWN":"聽說的……？從誰那裡？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......제 부모님입니다.","JPN":"……僕の両親からです。","ENG":"My parents.","TWN":"……我的父母。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부모님?","JPN":"両親？","ENG":"Your parents?","TWN":"你的父母？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저희 가족에게 대대로 전해 오는 특별한 혈통 같은 거죠.","JPN":"僕の一族に代々伝わる特別な血統みたいなものなんです。","ENG":"Dragon Blood is something that runs in my family.","TWN":"就像是我們家族代代相傳的特別血統一樣。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"물론 저도 처음 이런 이야기를 들었을 때는 어린 절 놀리는 거라고 생각했지만요, 하하.","JPN":"もちろん、僕も初めてこの話を聞いたときは、\\n自分が幼いからってからかってるんだと思いましたけどね、ハハ。","ENG":"When they first told me, I thought it was a lame joke.","TWN":"當然，我小時候第一次聽到這件事時，也以為是開玩笑呢，哈哈。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지난번에...... 부모님이 살해 당했다고 했었지?","JPN":"この前……両親は殺害されたって言ってたよね？","ENG":"Last time, you said your parents were murdered.","TWN":"上次……你說你的父母是被殺害的吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마...... 그 용혈이란 것과 관계가 있는 거야?","JPN":"まさか……その龍血とやらと何か関係があるの？","ENG":"Does it have anything to do with this Dragon Blood thing?","TWN":"難道……和那個龍血有關嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 관계가 없다고는 할 수 없겠죠.","JPN":"まあ、関係がないとは言えないでしょうね。","ENG":"Well, I can't say it was completely irrelevant.","TWN":"嗯，也不能說是沒關係吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 힘을 처음으로 쓰던 날 돌아가셨으니까요.","JPN":"その力を初めて使った日に亡くなってますから。","ENG":"They died the very first day that they actually used their powers.","TWN":"我的父母是在第一次使用那個力量的時候去世的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 누가...... 설마 이 녀석들이 한 짓인 거야?","JPN":"いったい誰がそんな……まさかこいつらの仕業なの？","ENG":"Who was it? Was it these bastards here?","TWN":"到底是誰……難道是這些傢伙們幹的嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그건 아닙니다만......","JPN":"そうではありませんが……","ENG":"No, but...","TWN":"那倒不是……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어쨌든 살해자가 누구인지는 중요한 게 아니에요.","JPN":"とにかく誰が殺害したかは重要ではありません。","ENG":"Well, who killed my parents isn't important anymore.","TWN":"總之，殺害他們的人是誰並不重要。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가 알고 싶은 건......","JPN":"僕が知りたいのは……","ENG":"What I want to know is","TWN":"我想知道的是……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이 용혈이란 게 대체 무엇인지......","JPN":"この龍血というのがいったい何なのか……","ENG":"what this Dragon Blood truly is,","TWN":"這個所謂的龍血到底是什麼……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 어째서 제 부모님들이 살해당할 수 밖에 없었는지......","JPN":"そして、どうして僕の親が殺されなければならなかったのか……","ENG":"and why my parents had to be killed.","TWN":"還有我父母為什麼非被殺死不可的……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 이유입니다.","JPN":"その理由についてです。","ENG":"That's all.","TWN":"原因。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 아주 오랫동안 그 이유를 찾고 있었어요.","JPN":"僕は長らくその理由を探してきましたが……","ENG":"I've been looking for a very long time,","TWN":"我花了很長的時間，都在尋找這個原因。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 별다른 소득은 없었죠.","JPN":"特段の成果はありませんでした。","ENG":"only to come up with nothing.","TWN":"但是一點收穫也沒有。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......미나 양을 만나기 전까지는요.","JPN":"……ミナさんに出会うまでは。","ENG":"That was until I met you, Mina.","TWN":"……在遇到米娜小姐之前。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배......","JPN":"先輩……","ENG":"Shiyoon...","TWN":"前輩……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 미나 양에게 아주 많은 기대를 하고 있습니다.","JPN":"僕はミナさんにとても期待してるんです。","ENG":"I have a lot of expectations for you, Mina.","TWN":"米娜小姐，我對妳有非常大的期待。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이야말로 제 의문을 해소해 줄 유일한 단서니까요.","JPN":"ミナさんこそ、僕の疑問を紐解く唯一の手掛かりですから。","ENG":"You're the only clue I have that will lead me to my answers.","TWN":"因為米娜小姐是解開我疑問的唯一線索。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양의 곁에 있으면...... 분명 저도 <color=#ffd34c>해답</color>을 찾게 될 겁니다.","JPN":"ミナさんのそばにいれば……僕もきっと、<color=#ffd34c>答え</color>を見つけられるでしょう。","ENG":"If I stay close to you, I'll be able to find the <color=#ffd34c>answer</color> I'm seeking.","TWN":"只要在米娜小姐身邊……我就一定可以找到<color=#ffd34c>答案</color>吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러니 제가 미나 양을 돕는 건 어찌 보면 당연한 일이죠.","JPN":"ですから、僕がミナさんを手伝うのは、ある意味当たり前なんです。","ENG":"So it's only natural that I'm helping you in every way I can.","TWN":"所以，我會幫助米娜小姐也是理所當然的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어때요? 대답이 되셨나요?","JPN":"どうです、答えになったでしょうか？","ENG":"What do you think, was that enough answer to you?","TWN":"怎麼樣？這樣回答妳的疑問了嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};